create table "public"."items" (
    "id" integer generated by default as identity not null,
    "codename" text not null,
    "display_name" text not null,
    "faction" text not null,
    "category" text not null,
    "crate_quantity" integer not null,
    "max_crate_stockpile" integer not null,
    "created_at" timestamp with time zone not null default now()
);


alter table "public"."items" enable row level security;

create table "public"."location" (
    "id" bigint generated by default as identity not null,
    "name" text not null,
    "created_at" timestamp with time zone not null default now(),
    "deleted_at" timestamp with time zone
);


alter table "public"."location" enable row level security;

create table "public"."stockpile" (
    "id" integer generated by default as identity not null,
    "location_id" bigint not null,
    "name" text not null,
    "code" text not null,
    "guild_sf" bigint not null,
    "role_sf" bigint not null,
    "created_by_sf" bigint not null,
    "created_at" timestamp with time zone not null default now(),
    "deleted_at" timestamp with time zone
);


alter table "public"."stockpile" enable row level security;

create table "public"."stockpile-items" (
    "id" integer generated by default as identity not null,
    "item_id" integer not null,
    "stockpile_id" integer not null,
    "quantity" integer not null,
    "guild_sf" bigint not null,
    "created_by_sf" bigint not null,
    "created_at" timestamp with time zone not null default now(),
    "crated" boolean not null
);


alter table "public"."stockpile-items" enable row level security;

create table "public"."stockpile-log" (
    "id" integer generated by default as identity not null,
    "stockpile_id" integer,
    "description" text not null,
    "guild_sf" bigint not null,
    "created_by_sf" bigint not null,
    "created_at" timestamp with time zone not null default now()
);


alter table "public"."stockpile-log" enable row level security;

CREATE UNIQUE INDEX items_pkey ON public.items USING btree (id);

CREATE UNIQUE INDEX location_id_key ON public.location USING btree (id);

CREATE UNIQUE INDEX location_pkey ON public.location USING btree (id);

CREATE UNIQUE INDEX "stockpile-items_id_key" ON public."stockpile-items" USING btree (id);

CREATE UNIQUE INDEX "stockpile-items_pkey" ON public."stockpile-items" USING btree (id);

CREATE UNIQUE INDEX "stockpile-log_id_key" ON public."stockpile-log" USING btree (id);

CREATE UNIQUE INDEX "stockpile-log_pkey" ON public."stockpile-log" USING btree (id);

CREATE UNIQUE INDEX stockpile_id_key ON public.stockpile USING btree (id);

CREATE UNIQUE INDEX stockpile_name_key ON public.stockpile USING btree (name);

CREATE UNIQUE INDEX stockpile_pkey ON public.stockpile USING btree (id);

alter table "public"."items" add constraint "items_pkey" PRIMARY KEY using index "items_pkey";

alter table "public"."location" add constraint "location_pkey" PRIMARY KEY using index "location_pkey";

alter table "public"."stockpile" add constraint "stockpile_pkey" PRIMARY KEY using index "stockpile_pkey";

alter table "public"."stockpile-items" add constraint "stockpile-items_pkey" PRIMARY KEY using index "stockpile-items_pkey";

alter table "public"."stockpile-log" add constraint "stockpile-log_pkey" PRIMARY KEY using index "stockpile-log_pkey";

alter table "public"."location" add constraint "location_id_key" UNIQUE using index "location_id_key";

alter table "public"."stockpile" add constraint "stockpile_id_key" UNIQUE using index "stockpile_id_key";

alter table "public"."stockpile" add constraint "stockpile_location_id_fkey" FOREIGN KEY (location_id) REFERENCES location(id) not valid;

alter table "public"."stockpile" validate constraint "stockpile_location_id_fkey";

alter table "public"."stockpile" add constraint "stockpile_name_key" UNIQUE using index "stockpile_name_key";

alter table "public"."stockpile-items" add constraint "stockpile-items_id_key" UNIQUE using index "stockpile-items_id_key";

alter table "public"."stockpile-items" add constraint "stockpile-items_item_id_fkey" FOREIGN KEY (item_id) REFERENCES items(id) not valid;

alter table "public"."stockpile-items" validate constraint "stockpile-items_item_id_fkey";

alter table "public"."stockpile-items" add constraint "stockpile-items_stockpile_id_fkey" FOREIGN KEY (stockpile_id) REFERENCES stockpile(id) not valid;

alter table "public"."stockpile-items" validate constraint "stockpile-items_stockpile_id_fkey";

alter table "public"."stockpile-log" add constraint "stockpile-log_id_key" UNIQUE using index "stockpile-log_id_key";

alter table "public"."stockpile-log" add constraint "stockpile-log_stockpile_id_fkey" FOREIGN KEY (stockpile_id) REFERENCES stockpile(id) not valid;

alter table "public"."stockpile-log" validate constraint "stockpile-log_stockpile_id_fkey";

